#include <stdio.h>
#define MOD 10000007
int main() {
    int T, n, m;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &n, &m);
        int A[n][m];
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                scanf("%d", &A[i][j]);
            }
        }
        long long sum = 0;
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                for (int k = 0; k < n; k++) {
                    if (m == 2) {
                        long long product = (long long)A[i][0] * A[j][1];
                        sum = (sum + product) % MOD;
                    } else if (m == 3) {
                        long long product = (long long)A[i][0] * A[j][1] * A[k][2];
                        sum = (sum + product) % MOD;
                    }
                }
            }
        }
        printf("%lld\n", sum);
    }
    return 0;
}

