import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int m = sc.nextInt();
            int[][] A = new int[n][m];
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < m; j++) {
                    A[i][j] = sc.nextInt();
                }
            }
            long sum = 0;
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < n; j++) {
                    for (int k = 0; k < n; k++) {
                        if (m == 2) {
                            long product = (long)A[i][0] * A[j][1];
                            sum = (sum + product) % 10000007;
                        } else if (m == 3) {
                            long product = (long)A[i][0] * A[j][1] * A[k][2];
                            sum = (sum + product) % 10000007;
                        }
                    }
                }
            }
            System.out.println(sum);
        }
    }
}

