const lines = require('fs').readFileSync(0, 'utf-8').trim().split('\n');
let i = 0;
const readline = () => lines[i++];
const T = parseInt(readline());
for (let t = 0; t < T; t++) {
    const [n, m] = readline().split(' ').map(x => parseInt(x));
    const A = [];
    for (let i = 0; i < n; i++) {
        A.push(readline().split(' ').map(x => parseInt(x)));
    }
    let sum = 0;
    for (let i = 0; i < n**m; i++) {
        let product = 1;
        let j = i;
        for (let k = 0; k < m; k++) {
            product = (product * A[j % n][k]) % 10000007;
            j = Math.floor(j / n);
        }
        sum = (sum + product) % 10000007;
    }
    console.log(sum);
}
